INSERT INTO posts (title, slug, content, excerpt, status, author_id, category_id, published_at, created_at, updated_at) VALUES
('Getting Started with GraphQL in .NET', 'getting-started-graphql-dotnet', 'GraphQL has transformed how we think about APIs. In this guide, we walk through setting up a GraphQL endpoint using .NET and Hot Chocolate.', 'A beginner-friendly introduction to GraphQL with .NET.', 'published', 1, 3, '2024-02-01 10:00:00', '2024-01-28 09:00:00', '2024-02-01 10:00:00'),
('Why I Switched from REST to GraphQL', 'why-i-switched-rest-to-graphql', 'After years of building REST APIs, I made the switch to GraphQL. Here is what convinced me and what I wish I had known earlier.', 'A personal account of moving from REST to GraphQL.', 'published', 1, 3, '2024-02-15 14:00:00', '2024-02-10 11:00:00', '2024-02-15 14:00:00'),
('Docker Compose for Local Development', 'docker-compose-local-dev', 'Stop installing databases on your machine. Docker Compose lets you spin up your entire stack in seconds.', 'Use Docker Compose to simplify your local dev environment.', 'published', 2, 4, '2024-02-20 09:30:00', '2024-02-18 08:00:00', '2024-02-20 09:30:00'),
('Kubernetes Secrets Management Best Practices', 'k8s-secrets-management', 'Managing secrets in Kubernetes is deceptively tricky. We cover sealed secrets, external secret operators, and vault integration.', 'How to manage sensitive config in Kubernetes safely.', 'published', 2, 4, '2024-03-01 11:00:00', '2024-02-25 14:00:00', '2024-03-01 11:00:00'),
('Introduction to Pandas for Data Analysis', 'intro-pandas-data-analysis', 'Pandas is the backbone of data analysis in Python. This tutorial covers DataFrames, filtering, grouping, and aggregation.', 'Learn the fundamentals of Pandas for data work.', 'published', 3, 5, '2024-03-10 10:00:00', '2024-03-05 09:00:00', '2024-03-10 10:00:00'),
('Building a Recommendation Engine with Python', 'recommendation-engine-python', 'We build a collaborative filtering recommendation engine from scratch using NumPy and scikit-learn.', 'Build your own recommendation system step by step.', 'published', 3, 5, '2024-03-20 13:00:00', '2024-03-15 10:00:00', '2024-03-20 13:00:00'),
('React Native vs Flutter in 2024', 'react-native-vs-flutter-2024', 'Both frameworks have matured significantly. We compare performance, developer experience, and ecosystem.', 'A 2024 comparison of the two leading cross-platform frameworks.', 'published', 4, 3, '2024-03-25 09:00:00', '2024-03-22 08:00:00', '2024-03-25 09:00:00'),
('Designing Accessible Forms', 'designing-accessible-forms', 'Good form design is accessible by default. We cover ARIA labels, focus management, and error handling patterns.', 'Make your web forms work for everyone.', 'published', 7, 3, '2024-04-01 10:30:00', '2024-03-28 09:00:00', '2024-04-01 10:30:00'),
('SQL Window Functions Explained', 'sql-window-functions-explained', 'Window functions unlock powerful analytics directly in SQL. We cover ROW_NUMBER, RANK, LAG, LEAD, and running totals.', 'A practical guide to SQL window functions.', 'published', 8, 2, '2024-04-05 11:00:00', '2024-04-02 10:00:00', '2024-04-05 11:00:00'),
('The Case for Rust in Backend Services', 'case-for-rust-backend', 'Rust is not just for systems programming. Its type system and performance make it compelling for web backends.', 'Why Rust deserves a place in your backend stack.', 'published', 6, 2, '2024-04-10 09:00:00', '2024-04-07 08:00:00', '2024-04-10 09:00:00'),
('CI/CD Pipeline Design Patterns', 'ci-cd-pipeline-patterns', 'A well-designed pipeline saves hours every week. We cover trunk-based development, feature flags, and canary releases.', 'Common patterns for effective CI/CD pipelines.', 'published', 2, 4, '2024-04-15 14:00:00', '2024-04-12 10:00:00', '2024-04-15 14:00:00'),
('TypeScript Generics Deep Dive', 'typescript-generics-deep-dive', 'Generics are the key to reusable TypeScript code. We explore constraints, conditional types, and mapped types.', 'Master TypeScript generics with practical examples.', 'published', 1, 2, '2024-04-20 10:00:00', '2024-04-17 09:00:00', '2024-04-20 10:00:00'),
('How to Prepare for a System Design Interview', 'system-design-interview-prep', 'System design interviews test your ability to think at scale. Here is a structured approach to ace them.', 'A framework for tackling system design interviews.', 'published', 6, 6, '2024-04-25 11:30:00', '2024-04-22 08:00:00', '2024-04-25 11:30:00'),
('OWASP Top 10: A Developer Guide', 'owasp-top-10-developer-guide', 'Security is everyone''s job. We walk through the OWASP Top 10 with code examples and mitigation strategies.', 'Understand and prevent the most common web vulnerabilities.', 'published', 5, 3, '2024-05-01 09:00:00', '2024-04-28 10:00:00', '2024-05-01 09:00:00'),
('Building Internal Tools That People Actually Use', 'internal-tools-people-use', 'Most internal tools are abandoned within months. Here is how to build ones that stick.', 'Design internal tools for adoption, not just functionality.', 'published', 9, 8, '2024-05-05 13:00:00', '2024-05-02 09:00:00', '2024-05-05 13:00:00'),
('Understanding Database Indexing', 'understanding-database-indexing', 'Indexes can make or break your query performance. We cover B-trees, composite indexes, and when NOT to index.', 'A practical guide to database indexing strategies.', 'published', 8, 2, '2024-05-10 10:00:00', '2024-05-07 08:00:00', '2024-05-10 10:00:00'),
('Migrating a Monolith to Microservices', 'migrating-monolith-microservices', 'Not every monolith needs splitting. We discuss when and how to decompose, with strategies for data migration.', 'A pragmatic guide to microservice migration.', 'published', 6, 2, '2024-05-15 09:30:00', '2024-05-12 10:00:00', '2024-05-15 09:30:00'),
('Writing Tests That Actually Help', 'writing-tests-that-help', 'Test coverage is a vanity metric. Focus on testing behavior, not implementation details.', 'How to write meaningful tests instead of chasing coverage.', 'published', 1, 7, '2024-05-20 11:00:00', '2024-05-17 09:00:00', '2024-05-20 11:00:00'),
('The State of WebAssembly in 2024', 'state-of-webassembly-2024', 'WebAssembly is expanding beyond the browser. We look at WASI, component model, and real-world adoption.', 'Where WebAssembly stands and where it is heading.', 'published', 10, 1, '2024-05-25 10:00:00', '2024-05-22 08:00:00', '2024-05-25 10:00:00'),
('Effective Code Reviews', 'effective-code-reviews', 'Code reviews should improve code AND grow engineers. Here are practices that achieve both.', 'How to give and receive better code reviews.', 'published', 9, 6, '2024-06-01 09:00:00', '2024-05-28 10:00:00', '2024-06-01 09:00:00'),
('GraphQL Subscriptions with WebSockets', 'graphql-subscriptions-websockets', 'Real-time data with GraphQL subscriptions. We set up a WebSocket transport and handle reconnection gracefully.', 'Add real-time capabilities to your GraphQL API.', 'published', 1, 3, '2024-06-05 14:00:00', '2024-06-02 09:00:00', '2024-06-05 14:00:00'),
('Python Type Hints: Beyond the Basics', 'python-type-hints-advanced', 'Type hints in Python go far beyond str and int. We cover Protocol, TypeVar, ParamSpec, and overloads.', 'Advanced Python typing for better code quality.', 'published', 3, 2, '2024-06-10 10:00:00', '2024-06-07 08:00:00', '2024-06-10 10:00:00'),
('Terraform vs Pulumi: Infrastructure as Code Showdown', 'terraform-vs-pulumi', 'Both tools have their strengths. We compare declarative HCL with imperative code for infrastructure management.', 'Choosing the right IaC tool for your team.', 'published', 2, 4, '2024-06-15 11:00:00', '2024-06-12 10:00:00', '2024-06-15 11:00:00'),
('Responsive Design Without Media Queries', 'responsive-design-no-media-queries', 'Modern CSS features like container queries, clamp(), and auto-fit grids reduce the need for breakpoints.', 'Build responsive layouts with modern CSS techniques.', 'published', 7, 3, '2024-06-20 09:30:00', '2024-06-17 08:00:00', '2024-06-20 09:30:00'),
('Negotiating Your Developer Salary', 'negotiating-developer-salary', 'Salary negotiation is a skill you can learn. Concrete tactics for getting paid what you are worth.', 'Practical salary negotiation advice for developers.', 'published', 9, 6, '2024-06-25 13:00:00', '2024-06-22 09:00:00', '2024-06-25 13:00:00'),
('Event-Driven Architecture with Kafka', 'event-driven-architecture-kafka', 'Kafka enables decoupled, scalable systems. We cover topics, consumer groups, exactly-once semantics, and schema registry.', 'A practical introduction to event-driven architecture.', 'published', 6, 2, '2024-07-01 10:00:00', '2024-06-28 08:00:00', '2024-07-01 10:00:00'),
('Prompt Engineering for Developers', 'prompt-engineering-developers', 'LLMs are tools, not magic. Learn structured prompting techniques that produce reliable, useful outputs.', 'How developers can get better results from AI models.', 'published', 3, 5, '2024-07-05 11:00:00', '2024-07-02 09:00:00', '2024-07-05 11:00:00'),
('HTTP/3 and QUIC: What Developers Need to Know', 'http3-quic-developers', 'HTTP/3 replaces TCP with QUIC for faster, more reliable connections. Here is what changes for your applications.', 'Understanding the next generation of HTTP.', 'published', 10, 1, '2024-07-10 09:00:00', '2024-07-07 10:00:00', '2024-07-10 09:00:00'),
('Building a Plugin System in .NET', 'plugin-system-dotnet', 'Extensible applications need a plugin architecture. We build one using AssemblyLoadContext and dependency injection.', 'Create a robust plugin system for .NET applications.', 'published', 8, 2, '2024-07-15 14:00:00', '2024-07-12 08:00:00', '2024-07-15 14:00:00'),
('Why Every Developer Should Write a Blog', 'developers-should-blog', 'Writing clarifies thinking. Blogging builds your reputation and helps others learn from your experience.', 'The benefits of technical blogging for your career.', 'published', 9, 6, '2024-07-20 10:00:00', '2024-07-17 09:00:00', '2024-07-20 10:00:00'),
('Zero-Downtime Database Migrations', 'zero-downtime-db-migrations', 'Schema changes should not take your application offline. We cover expand-contract, shadow tables, and online DDL.', 'Strategies for migrating database schemas safely.', 'published', 8, 4, '2024-07-25 11:00:00', '2024-07-22 10:00:00', '2024-07-25 11:00:00'),
('React Server Components Explained', 'react-server-components-explained', 'RSC changes the mental model of React. We clarify what runs where and how data flows between server and client.', 'Understand React Server Components from first principles.', 'published', 4, 3, '2024-08-01 09:00:00', '2024-07-28 08:00:00', '2024-08-01 09:00:00'),
('Monitoring Distributed Systems', 'monitoring-distributed-systems', 'Observability goes beyond dashboards. We cover the three pillars: logs, metrics, and traces with practical tooling.', 'A guide to monitoring complex distributed systems.', 'published', 2, 4, '2024-08-05 10:30:00', '2024-08-02 09:00:00', '2024-08-05 10:30:00'),
('Functional Programming Concepts for OOP Developers', 'fp-concepts-oop-developers', 'You do not need to switch languages to use FP. Immutability, pure functions, and composition work everywhere.', 'Practical FP concepts you can use in any language.', 'published', 6, 2, '2024-08-10 09:00:00', '2024-08-07 08:00:00', '2024-08-10 09:00:00'),
('API Rate Limiting Strategies', 'api-rate-limiting-strategies', 'Protect your API from abuse without hurting legitimate users. We cover token bucket, sliding window, and adaptive limits.', 'Implement effective rate limiting for your APIs.', 'published', 5, 3, '2024-08-15 11:00:00', '2024-08-12 10:00:00', '2024-08-15 11:00:00'),
('PostgreSQL Full-Text Search vs Elasticsearch', 'postgres-fts-vs-elasticsearch', 'PostgreSQL FTS is often good enough. We compare features, performance, and operational complexity.', 'When to use PostgreSQL search and when to reach for Elasticsearch.', 'published', 8, 2, '2024-08-20 10:00:00', '2024-08-17 09:00:00', '2024-08-20 10:00:00'),
('Building CLI Tools with Go', 'building-cli-tools-go', 'Go compiles to a single binary with no dependencies, making it perfect for CLI tools. We use Cobra and Viper.', 'Create professional CLI tools with Go.', 'published', 10, 7, '2024-08-25 09:30:00', '2024-08-22 08:00:00', '2024-08-25 09:30:00'),
('The Art of Technical Debt Management', 'technical-debt-management', 'Technical debt is not inherently bad. The key is tracking it, prioritizing it, and paying it down intentionally.', 'A pragmatic approach to managing technical debt.', 'published', 9, 8, '2024-09-01 13:00:00', '2024-08-28 10:00:00', '2024-09-01 13:00:00'),
('Implementing OAuth2 from Scratch', 'implementing-oauth2-scratch', 'Understanding OAuth2 deeply means building it once. We implement authorization code flow with PKCE step by step.', 'Build OAuth2 authorization code flow from the ground up.', 'published', 5, 7, '2024-09-05 10:00:00', '2024-09-02 09:00:00', '2024-09-05 10:00:00'),
('CSS Container Queries: A Practical Guide', 'css-container-queries-guide', 'Container queries let components respond to their container size, not the viewport. This changes component design.', 'Use container queries to build truly reusable components.', 'published', 7, 3, '2024-09-10 09:00:00', '2024-09-07 08:00:00', '2024-09-10 09:00:00'),
('gRPC vs REST: When to Use Which', 'grpc-vs-rest', 'gRPC shines for service-to-service communication. REST is better for public APIs. We break down the tradeoffs.', 'Choose the right protocol for your use case.', 'published', 6, 2, '2024-09-15 11:00:00', '2024-09-12 10:00:00', '2024-09-15 11:00:00'),
('Testing Microservices with Contract Tests', 'testing-microservices-contract-tests', 'Integration tests are slow and brittle. Contract tests verify service boundaries with speed and confidence.', 'Use contract testing to validate microservice interactions.', 'published', 1, 7, '2024-09-20 10:00:00', '2024-09-17 09:00:00', '2024-09-20 10:00:00'),
('How I Became a Staff Engineer', 'how-i-became-staff-engineer', 'The path to staff is not just about code. Influence, communication, and strategic thinking matter as much as technical skill.', 'Lessons learned on the path to staff engineering.', 'published', 6, 6, '2024-09-25 14:00:00', '2024-09-22 08:00:00', '2024-09-25 14:00:00'),
('Optimizing React Rendering Performance', 'optimizing-react-rendering', 'Unnecessary re-renders kill performance. We cover memo, useMemo, useCallback, and React DevTools profiling.', 'Practical techniques to speed up your React app.', 'published', 4, 3, '2024-10-01 09:00:00', '2024-09-28 08:00:00', '2024-10-01 09:00:00'),
('Introduction to WebRTC', 'introduction-webrtc', 'WebRTC enables peer-to-peer communication directly in the browser. We cover signaling, ICE candidates, and media streams.', 'Get started with real-time browser communication.', 'published', 10, 1, '2024-10-05 11:00:00', '2024-10-02 10:00:00', '2024-10-05 11:00:00'),
('Database Connection Pooling Explained', 'database-connection-pooling', 'Connection pools prevent your database from being overwhelmed. We cover sizing, timeouts, and common pitfalls.', 'Understand and configure database connection pools correctly.', 'draft', 8, 2, '2024-10-10 10:00:00', '2024-10-07 09:00:00', '2024-10-10 10:00:00'),
('Building Accessible Data Visualizations', 'accessible-data-visualizations', 'Charts and graphs exclude screen reader users by default. Here is how to make your visualizations inclusive.', 'Make data visualizations accessible to all users.', 'draft', 7, 3, NULL, '2024-10-12 08:00:00', '2024-10-12 08:00:00'),
('Rust Lifetimes Demystified', 'rust-lifetimes-demystified', 'Lifetimes are Rust''s most confusing feature. This guide uses visual diagrams and progressive examples to build intuition.', 'Finally understand Rust lifetimes.', 'draft', 10, 2, NULL, '2024-10-15 10:00:00', '2024-10-15 10:00:00'),
('The Future of Edge Computing', 'future-edge-computing', 'Edge functions are changing deployment. We explore Cloudflare Workers, Deno Deploy, and Vercel Edge Runtime.', 'Where edge computing is heading and why it matters.', 'archived', 2, 1, '2024-03-01 10:00:00', '2024-02-28 09:00:00', '2024-09-01 10:00:00'),
('Legacy Code Modernization Strategies', 'legacy-code-modernization', 'Every codebase ages. We discuss strangler fig, branch by abstraction, and incremental migration techniques.', 'Proven strategies for modernizing legacy systems.', 'archived', 6, 8, '2024-04-01 09:00:00', '2024-03-28 10:00:00', '2024-09-15 11:00:00');
