INSERT INTO comments (post_id, author_name, author_email, content, parent_comment_id, status, created_at) VALUES
(1, 'Alex Turner', 'alex.t@example.com', 'Great introduction! I have been looking for a clear GraphQL + .NET guide.', NULL, 'approved', '2024-02-02 08:15:00'),
(1, 'Mia Foster', 'mia.f@example.com', 'How does this compare to the REST controllers approach performance-wise?', NULL, 'approved', '2024-02-02 10:30:00'),
(1, 'Alex Turner', 'alex.t@example.com', 'Good question, Mia. In my experience the overhead is negligible for most workloads.', 2, 'approved', '2024-02-02 11:00:00'),
(2, 'Jordan Lee', 'jordan.l@example.com', 'I made the same switch last year. The tooling has improved so much.', NULL, 'approved', '2024-02-16 09:00:00'),
(3, 'Sam Brooks', 'sam.b@example.com', 'Docker Compose changed my life. No more conflicting Postgres versions.', NULL, 'approved', '2024-02-21 07:30:00'),
(3, 'Rachel Kim', 'rachel.k@example.com', 'Any tips for managing Docker Compose with multiple projects?', NULL, 'approved', '2024-02-21 14:00:00'),
(3, 'Sam Brooks', 'sam.b@example.com', 'I use separate compose files per project with unique network names.', 6, 'approved', '2024-02-21 15:30:00'),
(5, 'Taylor Wright', 'taylor.w@example.com', 'Pandas is still the best tool for quick data exploration. Nice writeup.', NULL, 'approved', '2024-03-11 08:00:00'),
(7, 'Chris Davis', 'chris.d@example.com', 'Flutter has caught up a lot in the last year, but React Native''s ecosystem is hard to beat.', NULL, 'approved', '2024-03-26 10:00:00'),
(7, 'Jordan Lee', 'jordan.l@example.com', 'I disagree. Flutter''s rendering engine gives it a clear performance advantage.', 9, 'approved', '2024-03-26 11:45:00'),
(7, 'Chris Davis', 'chris.d@example.com', 'Fair point on rendering, but hiring React Native devs is way easier.', 10, 'approved', '2024-03-26 13:00:00'),
(9, 'Pat Morgan', 'pat.m@example.com', 'Window functions are such an underused feature. Thanks for the clear examples.', NULL, 'approved', '2024-04-06 09:00:00'),
(10, 'Alex Turner', 'alex.t@example.com', 'Rust''s error handling alone makes it worth considering for backends.', NULL, 'approved', '2024-04-11 10:00:00'),
(12, 'Mia Foster', 'mia.f@example.com', 'Conditional types finally clicked for me after reading this. Thank you!', NULL, 'approved', '2024-04-21 08:30:00'),
(14, 'Sam Brooks', 'sam.b@example.com', 'Every developer should know the OWASP Top 10. Bookmarked.', NULL, 'approved', '2024-05-02 07:00:00'),
(14, 'Rachel Kim', 'rachel.k@example.com', 'Could you add an example for CSRF protection in single-page apps?', NULL, 'approved', '2024-05-02 14:00:00'),
(14, 'Pat Morgan', 'pat.m@example.com', 'SPAs typically use token-based auth which is not vulnerable to CSRF in the same way.', 16, 'approved', '2024-05-02 15:30:00'),
(16, 'Taylor Wright', 'taylor.w@example.com', 'The section on composite indexes was exactly what I needed.', NULL, 'approved', '2024-05-11 08:00:00'),
(18, 'Jordan Lee', 'jordan.l@example.com', 'Testing behavior over implementation is such important advice. Teams waste so much time on brittle tests.', NULL, 'approved', '2024-05-21 09:00:00'),
(18, 'Chris Davis', 'chris.d@example.com', 'How do you handle testing third-party API integrations?', NULL, 'approved', '2024-05-21 11:00:00'),
(18, 'Jordan Lee', 'jordan.l@example.com', 'Contract tests at the boundary, unit tests for your logic. Never mock what you do not own.', 20, 'approved', '2024-05-21 12:30:00'),
(21, 'Alex Turner', 'alex.t@example.com', 'WebSocket reconnection is the hardest part. Glad you covered it.', NULL, 'approved', '2024-06-06 09:00:00'),
(22, 'Mia Foster', 'mia.f@example.com', 'ParamSpec is a game changer for decorator typing. Nice deep dive.', NULL, 'approved', '2024-06-11 07:30:00'),
(25, 'Rachel Kim', 'rachel.k@example.com', 'The salary transparency section is really valuable. Thank you for writing this.', NULL, 'approved', '2024-06-26 10:00:00'),
(26, 'Pat Morgan', 'pat.m@example.com', 'We switched to Kafka last quarter and the decoupling has been transformative.', NULL, 'approved', '2024-07-02 08:00:00'),
(26, 'Sam Brooks', 'sam.b@example.com', 'What is the learning curve like for a team new to event-driven architectures?', 25, 'approved', '2024-07-02 10:00:00'),
(26, 'Pat Morgan', 'pat.m@example.com', 'Steep at first, but worth it. Start with a single event stream and expand from there.', 26, 'approved', '2024-07-02 11:30:00'),
(27, 'Taylor Wright', 'taylor.w@example.com', 'Prompt engineering feels like a real skill now. This is a good starting point.', NULL, 'approved', '2024-07-06 09:00:00'),
(29, 'Chris Davis', 'chris.d@example.com', 'AssemblyLoadContext is so much better than the old AppDomain approach.', NULL, 'approved', '2024-07-16 10:00:00'),
(31, 'Alex Turner', 'alex.t@example.com', 'Zero-downtime migrations are non-negotiable for production systems. Great patterns here.', NULL, 'approved', '2024-07-26 08:00:00'),
